import { useNavigate } from 'react-router-dom';
import { InfoCards, TeamCardTemp } from '../../components/Card';
import { FrstImageInfo } from '../../components/ImageInfo';
import Testmonial from '../../components/Testimonial';

function MainHome() {
    const navigate = useNavigate();
    const cardSet = [
        {
            "id": "01",
            "title": "Portfolio Shoots",
            "description": "Professional photoshoots that help models build a strong and impressive portfolio."
        },
        {
            "id": "02",
            "title": "Runway Training",
            "description": "Training sessions that help models improve confidence, posture, and runway walking skills."
        },
        {
            "id": "03",
            "title": "Brand Collaborations",
            "description": "Connecting models with brands for fashion promotions and creative campaigns."
        },
        {
            "id": "04",
            "title": "Casting Opportunities",
            "description": "Helping models participate in castings and auditions for fashion and commercial projects."
        },
        {
            "id": "05",
            "title": "Fashion Events",
            "description": "Providing professional models for fashion shows, exhibitions, and promotional events."
        },
        {
            "id": "06",
            "title": "Creative Productions",
            "description": "Supporting photoshoots, video shoots, and other fashion-related creative productions."
        }
    ]

    const teamCardSet = [
        {
            "id": 1, "imagesrc": "grayscale-photo-smiling-woman-wearing-turtleneck-top.jpg", "name": "Alice Johnson", "designation": "Software Engineer"
        },
        { "id": 2, "imagesrc": "front-view-authentic-woman-posing.jpg", "name": "Bob Smith", "designation": "Product Manager" },
        { "id": 3, "imagesrc": "front-view-smiley-woman-posing-black-white.jpg", "name": "Charlie Brown", "designation": "UX Designer" },
        { "id": 4, "imagesrc": "front-view-woman-posing-black-white.jpg", "name": "Diana Lee", "designation": "Quality Analyst" },
        { "id": 5, "imagesrc": "medium-shot-smiley-woman-posing-black-white.jpg", "name": "Ethan Williams", "designation": "DevOps Engineer" },
        { "id": 6, "imagesrc": "medium-shot-smiley-man-posing.jpg", "name": "Fiona Davis", "designation": "Frontend Developer" },
        { "id": 7, "imagesrc": "smiling-woman-posing-front-building.jpg", "name": "George Miller", "designation": "Backend Developer" },
        { "id": 8, "imagesrc": "black-white-minimal-portrait.jpg", "name": "Hannah Wilson", "designation": "HR Manager" }
    ]

    const handleRouting = (route, pageName) => {
        navigate(route, { state: pageName ? { pageName: pageName, imageSrc: "beautiful-beach-using-young-happy.jpg" } : null });
    };

    return (

        <>
            <section className='fade-in-section'>
                <div className='container-fluid pt-5 pb-5 cls-main-home1'>
                    <div className='cls-content-holder'>
                        <h1 className='mb-3 p-2 cls-shdow-text'>Where Talent Meets<br />Opportunity</h1>
                        <p className='cls-shdow-text'>Lorem ipsum dolor sit amet, consectetur adipiscing elit.
                            Fusce vitae egestas mi, vel dapibus diam. Mauris malesuada,
                            nisl non rutrum commodo, sem magna.</p>
                        <button className='btn commn-btn cls-shdow-text' onClick={() => handleRouting('/contact', "Contact")}>Contact Us</button>
                    </div>
                </div>
            </section>
            <section className=''>
                <div className='container-fluid p-0 nav-container' >
                    <div className='row'>
                        <div className='col-md-4 d-flex align-items-center justify-content-center p-3 cls-home-cont-imgs1 cls-info-cards column-1' >
                            <div className='text-center mx-2'>
                                <h5 className='p-2 cls-shdow-text'>Model Management</h5>
                                <p className='cls-shdow-text'>We guide and represent professional models, helping them connect with brands, designers, and creative projects.</p>
                                <button className='btn commn-btn cls-shdow-text' >Explore More</button>
                            </div>
                        </div>
                        <div className='col-md-4 d-flex align-items-center justify-content-center p-3 cls-home-cont-imgs2 cls-info-cards column-2' >
                            <div className='text-center mx-5'>
                                <h5 className='p-2 cls-shdow-text'>Portfolio Development</h5>
                                <p className='cls-shdow-text'>Professional photoshoots and portfolio creation designed to present models with confidence and style.</p>
                                <button className='btn commn-btn cls-shdow-text' >Explore More</button>
                            </div>
                        </div>
                        <div className='col-md-4 d-flex align-items-center justify-content-center p-3 cls-home-cont-imgs3 cls-info-cards column-3' >
                            <div className='text-center mx-5'>
                                <h5 className='p-2 cls-shdow-text'>Brand Campaigns</h5>
                                <p className='cls-shdow-text'>Providing models for fashion campaigns, advertisements, and promotional shoots for leading brands.</p>
                                <button className='btn commn-btn cls-shdow-text' >Explore More</button>
                            </div>
                        </div>
                    </div>
                </div>
            </section>
            <section className=''>
                <div className='container mt-5 mb-5'>
                    <div className='row cls-why-choose-us'>
                        <div className='col-md-8'>
                            <h1>Bold Fashion Talent</h1>
                        </div>
                        <div className='col-md-4 my-5'>
                            <p>We are a modern modeling consultancy focused on discovering and developing exceptional talent. Our team works closely with models and brands to create opportunities in fashion shows, commercial campaigns, and creative collaborations. With a strong focus on professionalism and creativity, we aim to build long-term relationships within the fashion and entertainment industry.</p>
                        </div>
                        <InfoCards infoArr={cardSet} />
                    </div>
                </div>
            </section>
            <section className='cls-odd pt-5 pb-5'>
                <div className='container'>
                    <div className='row'>
                        <div className='col-md-12 text-center'>
                            <h5 className='mb-4'>Our Team</h5>
                            <p>Our team is made up of passionate professionals dedicated to discovering and developing modeling talent. With experience in fashion, branding, and creative production, we work together to guide models and connect them with the right opportunities in the industry.</p>
                        </div>
                        <TeamCardTemp teamArr={teamCardSet} />
                    </div>
                </div>
            </section>
            <section className=''>
                <FrstImageInfo handleRouting={handleRouting} />
            </section>
            <section className='cls-odd'>
                <Testmonial handleRoute={handleRouting} />
            </section>
        </>
    )
}

export default MainHome;