export function FrstImageInfo({ handleRouting }) {
    const callhandler = (route, pagName) => {
        handleRouting(route, pagName)
    }
    return (
        <>
            <div className='container-fluid p-0'>
                <div className='row '>
                    <div className='col-md-6 maincls  m-0 p-0'>
                        <div className='cls-team-imgm'>
                        </div>
                    </div>
                    <div className='col-md-6 d-flex align-items-center justify-content-center maincls  m-0 p-0'>
                        <div className='cls-bigpicture-set1'>
                            <h5 className='mb-3'>Discover Your Potential</h5>
                            <p>We believe every model has a unique story and presence. Our agency focuses on guiding talent, building confidence, and creating opportunities that help individuals grow in the fashion and creative industry.</p>
                            <button className='btn commn-btn' onClick={() => callhandler('/contact', 'Contact')}>Contact Us</button>
                        </div>
                    </div>
                </div>
            </div>
        </>
    )
}

